def build_synthesis_prompt(question, fact_groups):
    facts_with_dates = []
    for fg in fact_groups:
        date = fg.get('published_date', 'unknown date')
        for fact in fg['facts']:
            facts_with_dates.append(f'[{fg["source_title"]} - {date}]: {fact}')

    return f'''
Answer: {question}

Facts (with publication dates):
{chr(10).join(facts_with_dates)}

IMPORTANT: If any source is more than 6 months old for a fast-changing topic,
note that the information may be outdated. Prefer more recent sources.
'''
```
Always include publication dates in the fact context and instruct the model to flag stale information.
